+  private getCursorOrder(opts: CrudOptions): [string, 'asc' | 'desc'][] | null {
+    if (!opts.orderBy) {
+      return null;
+    }
+
+    const orderBy = Array.isArray(opts.orderBy) ? opts.orderBy : [opts.orderBy];
+    const fields: [string, 'asc' | 'desc'][] = [];
+    for (const order of orderBy) {
+      for (const [field, direction] of Object.entries(order as object)) {
+        const normalized = this.normalizeCursorDirection(direction);
+        if (!normalized) {
+          throw new BadRequestException('orderBy must use asc or desc for cursor pagination');
+        }
+        fields.push([field, normalized]);
+      }
+    }
+
+    const idField = this.crudConfig.id_field as string;
+    if (!fields.some(([field]) => field === idField)) {
+      fields.push([idField, 'asc']);
+    }
+    return fields;
+  }
+
+  private normalizeCursorDirection(value: unknown): 'asc' | 'desc' | null {
+    if (value === 1) return 'asc';
+    if (value === -1) return 'desc';
+    const direction = String(value).toLowerCase().split(' ')[0];
+    return direction === 'asc' || direction === 'desc' ? direction : null;
+  }
+
+  private toOrderBy(order: [string, 'asc' | 'desc'][]): Record<string, string> {
+    return Object.fromEntries(order);
+  }
+
+  private decodeCursor(
+    cursor: string,
+    order: [string, 'asc' | 'desc'][],
+  ): Record<string, any> {
+    let payload: Record<string, any>;
+    try {
+      if (!/^(?:[A-Za-z0-9+/]{4})*(?:[A-Za-z0-9+/]{2}==|[A-Za-z0-9+/]{3}=)?$/.test(cursor)) {
+        throw new Error('invalid base64');
+      }
+      payload = JSON.parse(Buffer.from(cursor, 'base64').toString('utf8'));
+    } catch {
+      throw new BadRequestException('cursor must be Base64-encoded JSON');
+    }
+
+    if (!payload || Array.isArray(payload) || typeof payload !== 'object') {
+      throw new BadRequestException('cursor must be Base64-encoded JSON');
+    }
+    const expectedSort = order.map(([field, direction]) => `${field}:${direction}`).join(',');
+    if (payload.__sort !== expectedSort) {
+      throw new BadRequestException('cursor orderBy does not match request orderBy');
+    }
+    for (const [field] of order) {
+      if (!Object.prototype.hasOwnProperty.call(payload, field)) {
+        throw new BadRequestException(`cursor is missing ${field}`);
+      }
+    }
+    const idField = this.crudConfig.id_field as string;
+    if (!Object.prototype.hasOwnProperty.call(payload, idField)) {
+      throw new BadRequestException(`cursor is missing ${idField}`);
+    }
+    return payload;
+  }
+
+  private getCursorFilter(
+    order: [string, 'asc' | 'desc'][],
+    values: Record<string, any>,
+  ) {
+    return {
+      $or: order.map(([field, direction], index) => ({
+        ...Object.fromEntries(order.slice(0, index).map(([key]) => [key, values[key]])),
+        [field]: { [direction === 'asc' ? '$gt' : '$lt']: values[field] },
+      })),
+    };
+  }
+
+  private encodeCursor(order: [string, 'asc' | 'desc'][], entity: T): string {
+    const payload = Object.fromEntries(order.map(([field]) => [field, entity[field]]));
+    payload.__sort = order.map(([field, direction]) => `${field}:${direction}`).join(',');
+    return Buffer.from(JSON.stringify(payload)).toString('base64');
+  }
